vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // Calculate uAspect ratio correction
    float uAspect = uAspect.x / uAspect.y;

vUv = (vUvOriginal - 0.5) * vec2(uAspect, 1.0);
//vUv.x *= 0.8;  // Compress horizontally
float t = uTime;
vec3 o = vec3(0.0, 0.0, 0.0);  // Output color
float g = 0.0;  // Ray position
float e = 0.0;  // Scale factor
float s = 0.0;  // Distance field

for(float i = 0.0; i < 99.0; i++) {
    e = 2.0;
    vec3 p = multiply(vec3(vUv * g * 3.0, g), rotate3D(t * 0.5 - 8.0, vec3(2.0 + sin(t * 0.5) * 2.0, 1.0, 1.0)));
    p.z = mod(t * 0.5+q23 / 1.047 + p.z, e) - e;
    p.x += 0.6;

    for(int j = 0; j < 21; j++) {
        p = abs(p.zyx) - 1.0;
        s = dot(p, p);
        e /= s;
        p /= s + 0.03;
    }

    g -= p.z / e * 0.5 + 0.002;
    o += 1e-5 + hsv(p.y, p.y * 5.0 + s, 3.0) * 9e-6 * e / s / s;
}

ret = vec4(o, 1.0);

  fragColor = ret;
}

